={{ JSON.stringify({
  filter: {
    property: $json.propStatus,
    select: { equals: $json.statusScheduled },
  },
  sorts: [
    { property: $json.propScheduled, direction: 'ascending' },
  ],
  page_size: 30,
}) }}

parameters.jsCode:
/**
 * 取 Status=Scheduled 且 Scheduled<=now 的最舊一筆。
 */
const cfg = $('設定（請填 databaseId）').first().json;
const res = $input.first().json;
const pages = res.results || [];

function getRichText(prop) {
  if (!prop || prop.type !== 'rich_text') return '';
  return (prop.rich_text || []).map((t) => t.plain_text || '').join('');
}
function getSelect(prop) {
  if (!prop || prop.type !== 'select' || !prop.select) return '';
  return prop.select.name || '';
}
function getMulti(prop) {
  if (!prop || prop.type !== 'multi_select') return [];
  return (prop.multi_select || []).map((x) => x.name);
}
function getDateStart(prop) {
  if (!prop || prop.type !== 'date' || !prop.date) return null;
  return prop.date.start || null;
}

const now = Date.now();
const candidates = [];

for (const page of pages) {
  const p = page.properties || {};
  const st = getSelect(p[cfg.propStatus]);
  if (st !== cfg.statusScheduled) continue;
  const start = getDateStart(p[cfg.propScheduled]);
  if (!start) continue;
  const t = new Date(start).getTime();
  if (Number.isNaN(t) || t > now) continue;
  candidates.push({ page, t });
}

if (candidates.length === 0) return [];

candidates.sort((a, b) => a.t - b.t);
const { page } = candidates[0];
const pr = page.properties || {};
const content = getRichText(pr[cfg.propContent]);
const platforms = getMulti(pr[cfg.propPlatforms]);

return [
  {
    json: {
      ...cfg,
      pageId: page.id,
      notionUrl: page.url,
      content,
      platforms,
    },
  },
];

/**
 * 依序呼叫 Meta Graph（請在 n8n 環境變數設定 Token / ID）。
 * 使用 this.helpers.httpRequest，整段在同一執行內完成，最後只產出一筆給 Notion 更新。
 *
 * 辨識平台（不分大小寫）：facebook/fb、instagram/ig、threads
 * IG/Threads 端點為示意，請依官方文件改為正確兩段式流程。
 */
return (async () => {
const item = $input.first().json;
const content = String(item.content || '').trim();
const pageId = item.pageId;
const platforms = Array.isArray(item.platforms) ? item.platforms : [];

const parts = [];
const errors = [];

const httpRequest = this.helpers.httpRequest.bind(this);
async function graphGet(url, qs) {
  const u = new URL(url);
  for (const [k, v] of Object.entries(qs || {})) {
    if (v !== undefined && v !== null && v !== '') u.searchParams.set(k, String(v));
  }
  return httpRequest({
    method: 'GET',
    url: u.toString(),
    json: true,
  });
}

for (const raw of platforms) {
  const plat = String(raw || '').trim();
  const key = plat.toLowerCase();
  try {
    if (key === 'facebook' || key === 'fb') {
      const pid = process.env.FACEBOOK_PAGE_ID;
      const tok = process.env.FACEBOOK_PAGE_ACCESS_TOKEN;
      const r = await graphGet(`https://graph.facebook.com/v21.0/${pid}/feed`, {
        message: content,
        access_token: tok,
      });
      const id = r.id || r.post_id;
      parts.push(id ? `FB:${id}` : 'FB:ok');
    } else if (key === 'instagram' || key === 'ig') {
      const ig = process.env.INSTAGRAM_BUSINESS_ACCOUNT_ID;
      const tok = process.env.INSTAGRAM_ACCESS_TOKEN;
      const img = process.env.INSTAGRAM_PLACEHOLDER_IMAGE_URL || 'https://example.com/placeholder.png';
      const r = await graphGet(`https://graph.facebook.com/v21.0/${ig}/media`, {
        image_url: img,
        caption: content,
        access_token: tok,
      });
      const id = r.id;
      parts.push(id ? `IG:${id}` : 'IG:ok');
    } else if (key === 'threads') {
      const uid = process.env.THREADS_USER_ID;
      const tok = process.env.THREADS_ACCESS_TOKEN;
      const r = await graphGet(`https://graph.facebook.com/v21.0/${uid}/threads`, {
        media_type: 'TEXT',
        text: content,
        access_token: tok,
      });
      const id = r.id;
      parts.push(id ? `Threads:${id}` : 'Threads:ok');
    } else {
      parts.push(`${plat}:skipped`);
    }
  } catch (e) {
    errors.push(`${plat}:${e.message || e}`);
  }
}

const postIdsLine = [...parts, ...errors.map((e) => `ERR:${e}`)]
  .join(' | ')
  .slice(0, 2000);

return [
  {
    json: {
      pageId,
      propStatus: item.propStatus,
      propPostId: item.propPostId,
      propPublishedAt: item.propPublishedAt,
      statusPublished: item.statusPublished,
      postIdsLine,
      publishedAtIso: new Date().toISOString(),
    },
  },
];
})();

